    private fun setupActivityResultLaunchers() {
        cameraPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestMultiplePermissions()
        ) { permissions ->
            val allGranted = permissions.values.all { it }
            if (allGranted) {
                pendingCameraCallback?.let { callback ->
                    evaluateJavascript("$callback({\"granted\": true})")
                }
                pendingWebPermissionRequest?.grant(pendingWebPermissionRequest?.resources)
            } else {
                pendingCameraCallback?.let { callback ->
                    evaluateJavascript("$callback({\"granted\": false, \"error\": \"Camera permission denied\"})")
                }
                pendingWebPermissionRequest?.deny()
            }
            pendingCameraCallback = null
            pendingWebPermissionRequest = null
        }

        notificationPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { granted ->
            if (granted) {
                getFirebaseToken { token ->
                    pendingNotificationCallback?.let { callback ->
                        evaluateJavascript("$callback({\"granted\": true, \"token\": \"${sanitizeForJs(token)}\"})")
                    }
                    pendingNotificationCallback = null
                }
            } else {
                pendingNotificationCallback?.let { callback ->
                    evaluateJavascript("$callback({\"granted\": false, \"error\": \"Notification permission denied\"})")
                }
                pendingNotificationCallback = null
            }
        }

        fileChooserLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            if (result.resultCode == Activity.RESULT_OK) {
                val data = result.data
                val results: Array<Uri>? = if (data?.data != null) {
                    arrayOf(data.data!!)
                } else if (cameraImageUri != null) {
                    arrayOf(cameraImageUri!!)
                } else {
                    null
                }
                fileUploadCallback?.onReceiveValue(results ?: arrayOf())
            } else {
                fileUploadCallback?.onReceiveValue(arrayOf())
            }
            fileUploadCallback = null
        }
    }

