    private fun isAllowedUrl(url: String): Boolean {
        return try {
            val uri = Uri.parse(url)
            val host = uri.host ?: return false
            val scheme = uri.scheme ?: return false
            scheme == "https" && allowedDomains.any { domain ->
                host == domain || host.endsWith(".$domain")
            }
        } catch (e: Exception) {
            false
        }
    }

    fun evaluateJavascript(script: String) {
        runOnUiThread {
            webView.evaluateJavascript(script, null)
        }
    }

    fun requestCameraPermission(callbackName: String?) {
        pendingCameraCallback = callbackName
        val permissions = arrayOf(Manifest.permission.CAMERA)
        if (permissions.all {
                ContextCompat.checkSelfPermission(this, it) == PackageManager.PERMISSION_GRANTED
            }) {
            callbackName?.let { callback ->
                evaluateJavascript("$callback({\"granted\": true})")
            }
            pendingCameraCallback = null
        } else {
            cameraPermissionLauncher.launch(permissions)
        }
    }

    fun requestNotificationPermission(callbackName: String?) {
        pendingNotificationCallback = callbackName
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (ContextCompat.checkSelfPermission(
                    this,
                    Manifest.permission.POST_NOTIFICATIONS
                ) == PackageManager.PERMISSION_GRANTED
            ) {
                getFirebaseToken { token ->
                    callbackName?.let { callback ->
                        evaluateJavascript("$callback({\"granted\": true, \"token\": \"${sanitizeForJs(token)}\"})")
                    }
                    pendingNotificationCallback = null
                }
            } else {
                notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
            }
        } else {
            getFirebaseToken { token ->
                callbackName?.let { callback ->
                    evaluateJavascript("$callback({\"granted\": true, \"token\": \"${sanitizeForJs(token)}\"})")
                }
                pendingNotificationCallback = null
            }
        }
    }

    private fun getFirebaseToken(onToken: (String) -> Unit) {
        FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
            if (task.isSuccessful) {
                onToken(task.result ?: "")
            } else {
                onToken("")
            }
        }
    }

    private fun createImageFile(): Uri? {
        val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
        val imageFileName = "JPEG_${timeStamp}_"

        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
            val contentValues = ContentValues().apply {
                put(MediaStore.MediaColumns.DISPLAY_NAME, "$imageFileName.jpg")
                put(MediaStore.MediaColumns.MIME_TYPE, "image/jpeg")
                put(MediaStore.MediaColumns.RELATIVE_PATH, Environment.DIRECTORY_PICTURES)
            }
            contentResolver.insert(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, contentValues)
        } else {
            val storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES)
            val imageFile = File.createTempFile(imageFileName, ".jpg", storageDir)
            FileProvider.getUriForFile(
                this,
                "${applicationContext.packageName}.fileprovider",
                imageFile
            )
        }
    }

    private inner class SecureWebViewClient : WebViewClient() {
        override fun shouldOverrideUrlLoading(
            view: WebView?,
            request: WebResourceRequest?
        ): Boolean {
            val url = request?.url?.toString() ?: return true
            return if (isAllowedUrl(url)) {
                false
            } else {
                Log.w("WebView", "Blocked navigation to untrusted URL: $url")
                true
            }
        }

        override fun onReceivedError(
            view: WebView?,
            request: WebResourceRequest?,
            error: WebResourceError?
        ) {
            super.onReceivedError(view, request, error)
            if (request?.isForMainFrame == true) {
                view?.loadData(
                    getErrorHtml(),
                    "text/html",
                    "UTF-8"
                )
            }
        }

        override fun onReceivedSslError(
            view: WebView?,
            handler: android.webkit.SslErrorHandler?,
            error: android.net.http.SslError?
        ) {
            handler?.cancel()
            Log.e("WebView", "SSL Error: ${error?.primaryError}")
        }
    }

    private inner class HybridWebChromeClient : WebChromeClient() {
        override fun onPermissionRequest(request: PermissionRequest?) {
            request?.let { req ->
                val resources = req.resources
                if (resources.contains(PermissionRequest.RESOURCE_VIDEO_CAPTURE)) {
                    if (ContextCompat.checkSelfPermission(
                            this@MainActivity,
                            Manifest.permission.CAMERA
                        ) == PackageManager.PERMISSION_GRANTED
                    ) {
                        req.grant(arrayOf(PermissionRequest.RESOURCE_VIDEO_CAPTURE))
                    } else {
                        pendingWebPermissionRequest = req
                        cameraPermissionLauncher.launch(arrayOf(Manifest.permission.CAMERA))
                    }
                } else {
                    req.deny()
                }
            }
        }

        override fun onShowFileChooser(
            webView: WebView?,
            filePathCallback: ValueCallback<Array<Uri>>?,
            fileChooserParams: FileChooserParams?
        ): Boolean {
            fileUploadCallback?.onReceiveValue(null)
            fileUploadCallback = filePathCallback

            val takePictureIntent = android.content.Intent(MediaStore.ACTION_IMAGE_CAPTURE)
            cameraImageUri = createImageFile()
            cameraImageUri?.let {
                takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, it)
            }

            val contentSelectionIntent = android.content.Intent(android.content.Intent.ACTION_GET_CONTENT).apply {
                addCategory(android.content.Intent.CATEGORY_OPENABLE)
                type = fileChooserParams?.acceptTypes?.firstOrNull() ?: "image/*"
            }

            val chooserIntent = android.content.Intent.createChooser(contentSelectionIntent, "Select")
            chooserIntent.putExtra(
                android.content.Intent.EXTRA_INITIAL_INTENTS,
                arrayOf(takePictureIntent)
            )

            fileChooserLauncher.launch(chooserIntent)
            return true
        }

        override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
            if (BuildConfig.DEBUG) {
                Log.d(
                    "WebView",
