    companion object {
        fun sanitizeForJs(input: String): String {
            return input
                .replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("'", "\\'")
                .replace("\n", "\\n")
                .replace("\r", "\\r")
                .replace("<", "\\u003c")
                .replace(">", "\\u003e")
        }

        fun isValidCallbackName(name: String?): Boolean {
            if (name == null) return false
            val pattern = Regex("^[a-zA-Z_][a-zA-Z0-9_.]*$")
            return pattern.matches(name) && name.length <= 128
        }
    }
