class NativeBridge(private val activity: MainActivity) {

    private val securePrefs: SharedPreferences by lazy {
        val masterKey = MasterKey.Builder(activity)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()

        EncryptedSharedPreferences.create(
            activity,
            "secure_hybrid_prefs",
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    private val maxKeyLength = 256
    private val maxValueLength = 10 * 1024 // 10KB per value

    @JavascriptInterface
    fun requestCameraAccess(callbackName: String?) {
        if (!MainActivity.isValidCallbackName(callbackName)) {
            Log.w("NativeBridge", "Invalid callback name for camera access")
            return
        }
        activity.runOnUiThread {
            activity.requestCameraPermission(callbackName)
        }
    }

    @JavascriptInterface
    fun hasCameraPermission(): Boolean {
        return ContextCompat.checkSelfPermission(
            activity,
            Manifest.permission.CAMERA
        ) == PackageManager.PERMISSION_GRANTED
    }

    @JavascriptInterface
    fun setItem(key: String?, value: String?): Boolean {
        if (key.isNullOrBlank() || key.length > maxKeyLength) {
            Log.w("NativeBridge", "Invalid storage key")
            return false
        }
        if (value != null && value.length > maxValueLength) {
            Log.w("NativeBridge", "Value too large for key: $key")
            return false
        }
        return try {
            val sanitizedKey = sanitizeStorageKey(key)
            securePrefs.edit().putString(sanitizedKey, value).apply()
            true
        } catch (e: Exception) {
            Log.e("NativeBridge", "Error setting item", e)
            false
        }
    }

    @JavascriptInterface
    fun getItem(key: String?): String? {
        if (key.isNullOrBlank() || key.length > maxKeyLength) {
            return null
        }
        return try {
            val sanitizedKey = sanitizeStorageKey(key)
            securePrefs.getString(sanitizedKey, null)
        } catch (e: Exception) {
            Log.e("NativeBridge", "Error getting item", e)
            null
        }
    }

    @JavascriptInterface
    fun removeItem(key: String?): Boolean {
        if (key.isNullOrBlank() || key.length > maxKeyLength) {
            return false
        }
        return try {
            val sanitizedKey = sanitizeStorageKey(key)
            securePrefs.edit().remove(sanitizedKey).apply()
            true
        } catch (e: Exception) {
            Log.e("NativeBridge", "Error removing item", e)
            false
        }
    }

    @JavascriptInterface
    fun clearStorage(): Boolean {
        return try {
            securePrefs.edit().clear().apply()
            true
        } catch (e: Exception) {
            Log.e("NativeBridge", "Error clearing storage", e)
            false
        }
    }

    @JavascriptInterface
    fun getStorageKeys(): String {
        return try {
            val keys = securePrefs.all.keys.toList()
            JSONObject().apply {
                put("keys", org.json.JSONArray(keys))
            }.toString()
        } catch (e: Exception) {
            "{\"keys\":[]}"
        }
    }

    @JavascriptInterface
    fun requestPushNotifications(callbackName: String?) {
        if (!MainActivity.isValidCallbackName(callbackName)) {
            Log.w("NativeBridge", "Invalid callback name for notifications")
            return
        }
        activity.runOnUiThread {
            activity.requestNotificationPermission(callbackName)
        }
    }

    @JavascriptInterface
    fun subscribeToPushTopic(topic: String?): Boolean {
        if (topic.isNullOrBlank() || !isValidTopic(topic)) {
            return false
        }
        return try {
            FirebaseMessaging.getInstance().subscribeToTopic(topic)
            true
        } catch (e: Exception) {
            Log.e("NativeBridge", "Error subscribing to topic", e)
            false
        }
    }

    @JavascriptInterface
    fun unsubscribeFromPushTopic(topic: String?): Boolean {
        if (topic.isNullOrBlank() || !isValidTopic(topic)) {
            return false
        }
        return try {
            FirebaseMessaging.getInstance().unsubscribeFromTopic(topic)
            true
        } catch (e: Exception) {
            Log.e("NativeBridge", "Error unsubscribing from topic", e)
            false
        }
    }

    @JavascriptInterface
    fun getDeviceInfo(): String {
        return try {
            JSONObject().apply {
                put("platform", "android")
                put("osVersion", Build.VERSION.RELEASE)
                put("sdkVersion", Build.VERSION.SDK_INT)
                put("model", Build.MODEL)
                put("manufacturer", Build.MANUFACTURER)
            }.toString()
        } catch (e: Exception) {
            "{\"platform\":\"android\"}"
        }
    }

    @JavascriptInterface
    fun showToast(message: String?) {
        if (message.isNullOrBlank() || message.length > 200) return
        val sanitized = message.take(200)
        activity.runOnUiThread {
            Toast.makeText(activity, sanitized, Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun getAppVersion(): String {
        return try {
            val pInfo = activity.packageManager.getPackageInfo(activity.packageName, 0)
            JSONObject().apply {
                put("versionName", pInfo.versionName)
                put("versionCode", if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                    pInfo.longVersionCode
                } else {
                    @Suppress("DEPRECATION")
                    pInfo.versionCode.toLong()
                })
            }.toString()
        } catch (e: Exception) {
            "{}"
        }
    }

    private fun sanitizeStorageKey(key: String): String {
        return key.replace(Regex("[^a-zA-Z0-9_.-]"), "_")
    }

    private fun isValidTopic(topic: String): Boolean {
        val pattern = Regex("^[a-zA-Z0-9-_.~%]{1,900}$")
        return pattern.matches(topic)
    }
}


class HybridFirebaseMessagingService : FirebaseMessagingService() {

    override fun onNewToken(token: String) {
        super.onNewToken(token)
        Log.d("FCM", "New token: $token")
        // Send token to your server
        sendTokenToServer(token)
    }

    override fun onMessageReceived(message: RemoteMessage) {
        super.onMessageReceived(message)

        val title = message.notification?.title ?: message.data["title"] ?: "Notification"
        val body = message.notification?.body ?: message.data["body"] ?: ""
        val data = message.data

        showNotification(title, body, data)
    }

    private fun sendTokenToServer(token: String) {
        // Implement server-side token registration
        Log.d("FCM", "Token should be sent to server: $token")
    }

    private fun showNotification(title: String, body: String, data: Map<String, String>) {
        val channelId = "hybrid_app_channel"

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = android.app.NotificationChannel(
                channelId,
                "App Notifications",
                android.app.NotificationManager.IMPORTANCE_DEFAULT
            ).apply {
                description = "Notifications from the app"
            }
            val notificationManager = getSystemService(android.app.NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }

        val intent = android.content.Intent(this, MainActivity::class.java).apply {
            flags = android.content.Intent.FLAG_ACTIVITY_NEW_TASK or
                    android.content.Intent.FLAG_ACTIVITY_CLEAR_TOP
            data.forEach { (key, value) ->
                putExtra(key, value)
            }
        }

        val pendingIntent = android.app.PendingIntent.getActivity(
            this,
            0,
            intent,
            android.app.PendingIntent.FLAG_ONE_SHOT or android.app.PendingIntent.FLAG_IMMUTABLE
        )

        val notification = androidx.core.app.NotificationCompat.Builder(this, channelId)
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setContentTitle(title)
            .setContentText(body)
            .setAutoCancel(true)
            .setContentIntent(pendingIntent)
            .setPriority(androidx.core.app.NotificationCompat.PRIORITY_DEFAULT)
            .build()

        val notificationManager =
            getSystemService(Context.NOTIFICATION_SERVICE) as android.app.NotificationManager

        if (ContextCompat.checkSelfPermission(
                this,
                Manifest.permission.POST_NOTIFICATIONS
            ) == PackageManager.PERMISSION_GRANTED || Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU
        ) {
            notificationManager.notify(System.currentTimeMillis().toInt(), notification)
        }
    }
}